void UIFlowWndEdogMsg_DisplayUIMsg_UniqueSky(void)
{
	AlarmTypeNow = EdogInfo_SentenceA.EDOG_AlarmType;
	DBG_IND("GPSRadar_GetCASNesting()=%d GPSRadar_GetCurrentCASStart()=%d\r\n",GPSRadar_GetCASNesting(),GPSRadar_GetCurrentCASStart());
	if(((GetGPSAvgRemainSec() <= 0)||(AlarmTypePrev==0xC4)||(GPSRadar_GetCurrentCASDistance()==0))&&(AlarmTypeNow==0xff)&&((GPSRadar_GetCASNesting()==0)||((GPSRadar_GetCASNesting()!=0)&&(GPSRadar_GetCurrentCASStart()!=SPEED_DECTION_START))))
		//close window
	{
	    //g_bEdogShowUI=FALSE;
	    g_bAvgCalStart = FALSE;
    	Ux_CloseWindow(&UIFlowWndEdogMsg_UniqueSkyCtrl,0);
    	UISound_Play(DEMOSOUND_SOUND_EP43_TONE_DONDDD);
	}
	else 
	{
		if(AlarmTypeNow!=0xff)
		{
			FlowMovie_WakeUpLCDBacklight();
			//Show Edog Alarm UI & Play Voice
			if(((EdogInfo_SentenceA.EDOG_AlarmType>=0x40)&&(EdogInfo_SentenceA.EDOG_AlarmType<=0x4F))
				||(EdogInfo_SentenceA.EDOG_AlarmType==0xC4))
			{
				Cur_GPS_Speed = (UINT16)GPSRec_GetGPS_Speed();
				#if 0
				if((GPSRadar_GetCASNesting()!=0)
					&&(GPSRadar_GetCurrentCASStart()==SPEED_DECTION_START))
				{
					Display_SpeedLimit_UniqueSky(GPSRadar_GetCurrentCASOverspeed()/10);
				}
				else 
				{
					Display_SpeedLimit_UniqueSky(GPSRadar_GetCurrentCASOverspeed());
				}
				#endif
				UIFlowWndEdogMsg_UpdateUI_UniqueSky();
				if((AlarmTypeNow==0xC4)&&(AlarmTypeNow!=AlarmTypePrev))
				{
					FlowMovie_EdogAlarmVoice(AlarmTypeNow);
				}
			}
			else
			{
			   	//Ux_CloseWindow(&UIFlowWndEdogMsg_UniqueSkyCtrl,0);
				//Ux_Redraw();
    			//UISound_Play(DEMOSOUND_SOUND_EP43_TONE_DONDDD);
    			if(FlowMovie_isEdogTypeValid(AlarmTypeNow))
				{
					Ux_OpenWindow(&UIFlowWndEdogMsgCtrl, 1,AlarmTypeNow);
					Ux_Redraw();
					FlowMovie_EdogAlarmVoice(AlarmTypeNow);
    			}
			}
		}
		else
		{
			Cur_GPS_Speed = (UINT16)GPSRec_GetGPS_Speed();
			#if 0
			if((GPSRadar_GetCASNesting()!=0)
				&&(GPSRadar_GetCurrentCASStart()==SPEED_DECTION_START))
			{
				Display_SpeedLimit_UniqueSky(GPSRadar_GetCurrentCASOverspeed()/10);
			}
			else 
			{
				Display_SpeedLimit_UniqueSky(GPSRadar_GetCurrentCASOverspeed());
			}
			#endif
			UIFlowWndEdogMsg_UpdateUI_UniqueSky();
		}
		AlarmTypePrev = AlarmTypeNow;
		DBG_IND("AlarmTypeNow = %d AlarmTypePrev=%d\r\n",AlarmTypeNow,AlarmTypePrev);
	}
    Ux_Redraw();
}

INT32 UIFlowWndEdogMsg_UniqueSky_OnOpen(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
	UINT8 type	= EdogInfo_SentenceA.EDOG_AlarmType;
	if (paramNum > 0){
		AlarmTypePrev = paramArray[0];
		AlarmTypeNow =	paramArray[0];
	}else{
		AlarmTypePrev = type;
		AlarmTypePrev = type;
	}
    DBG_IND("^G UIFlowWndEdogMsg_UniqueSky_OnOpen---AlarmTypePrev=%d---AlarmTypeNow=%d paramNum=%d\r\n",AlarmTypePrev,AlarmTypeNow,paramNum);
	UxCtrl_SetShow(&UIFlowWndEdogMsg_UniqueSky_PanelCtrl, TRUE);
    UIFlowWndEdogMsg_DisplayUIMsg_UniqueSky();
	Display_SpeedLimit_UniqueSky(GPSRadar_GetCurrentCASOverspeed()/10);

    Ux_DefaultEvent(pCtrl,NVTEVT_OPEN_WINDOW,paramNum,paramArray);
    return NVTEVT_CONSUME;
}

INT32 UIFlowWndEdogMsg_UniqueSky_OnClose(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
    DBG_DUMP("^G UIFlowWndEdogMsg_UniqueSky_OnClose---------- \r\n");
    if(gUIGPSSignalDetTimerID != NULL_TIMER)
    {
        GxTimer_StopTimer(&gUIGPSSignalDetTimerID);
    }

    //g_bEdogMsgOff = TRUE;
	Ux_FlushEventByRange(NVTEVT_KEY_EDOG_ALARM, NVTEVT_KEY_EDOG_ALARM);
    Ux_DefaultEvent(pCtrl,NVTEVT_CLOSE_WINDOW,paramNum,paramArray);
    return NVTEVT_CONSUME;
}

INT32 UIFlowWndEdogMsg_UniqueSky_OnKeyLeft(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
    UINT32  uiKeyAct;
    uiKeyAct = paramArray[0];

    switch (uiKeyAct)
    {
    case NVTEVT_KEY_RELEASE:
        g_bManualCloseEdogWnd = TRUE;
        Ux_CloseWindow(&UIFlowWndEdogMsg_UniqueSkyCtrl,0);	
        break;
    }	
    return NVTEVT_CONSUME;
}

INT32 UIFlowWndEdogMsg_UniqueSky_OnEdogShowUI(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
	//DBG_DUMP("***********UIFlowWndEdogMsg_UniqueSky_OnTimer\r\n");
	UIFlowWndEdogMsg_DisplayUIMsg_UniqueSky();

	return NVTEVT_CONSUME;
}

INT32 UIFlowWndEdogMsg_UniqueSky_OnTimer(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
    UINT32  uiEvent;    
	uiEvent = paramNum ? paramArray[0] : 0;

	switch(uiEvent)
	{
    case NVTEVT_1SEC_TIMER:
        //DBG_DUMP("UIFlowWndEdogMsg_UniqueSky_OnTimer -> NVTEVT_1SEC_TIMER \r\n");
		
        UIFlowWndEdogMsg_DisplayUIMsg_UniqueSky();
        break;
    }
	return NVTEVT_CONSUME;
}

INT32 UIFlowWndEdogMsg_UniqueSky_OnCustom1(VControl *pCtrl, UINT32 paramNum, UINT32 *paramArray)
{
    if (System_GetState(SYS_STATE_CURRSUBMODE) == SYS_SUBMODE_WIFI) {
        return UIFlowWndWiFiMovie_OnCustom1(pCtrl, paramNum, paramArray);
    } else {
        return UIFlowWndMovie_OnCustom1(pCtrl, paramNum, paramArray);
    }
}


